import { db } from './config';
import { 
  collection, 
  getDocs, 
  getDoc, 
  doc, 
  query, 
  where,
  addDoc,
  updateDoc,
  deleteDoc,
  orderBy,
  Timestamp,
  limit,
  setDoc
} from 'firebase/firestore';
import { mockCompanies, mockRaffles } from './mockData';
import { Company, Raffle, CarFeature, CarSpecifications } from '../types';

// Use mock data for development
const USE_MOCK_DATA = false;

// Collections
export const companiesCollection = collection(db, 'companies');
export const rafflesCollection = collection(db, 'raffles');
export const carFeaturesCollection = collection(db, 'carFeatures');

// Get all companies
export const getCompanies = async () => {
  if (USE_MOCK_DATA) {
    return mockCompanies;
  }

  const snapshot = await getDocs(companiesCollection);
  return snapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  })) as Company[];
};

// Get a specific company
export const getCompany = async (companyId: string) => {
  if (USE_MOCK_DATA) {
    const company = mockCompanies.find(c => c.id === companyId);
    return company || null;
  }

  const docRef = doc(db, 'companies', companyId);
  const docSnap = await getDoc(docRef);
  
  if (docSnap.exists()) {
    return {
      id: docSnap.id,
      ...docSnap.data()
    } as Company;
  } else {
    return null;
  }
};

// Create a new company
export const createCompany = async (company: Omit<Company, 'id'>) => {
  if (USE_MOCK_DATA) return { id: 'mock-id-' + Date.now() };
  
  const docRef = await addDoc(companiesCollection, {
    ...company,
    createdAt: Timestamp.now()
  });
  
  return { id: docRef.id };
};

// Update a company
export const updateCompany = async (companyId: string, data: Partial<Company>) => {
  if (USE_MOCK_DATA) return true;
  
  const docRef = doc(db, 'companies', companyId);
  await updateDoc(docRef, data);
  
  return true;
};

// Delete a company
export const deleteCompany = async (companyId: string) => {
  if (USE_MOCK_DATA) return true;
  
  const docRef = doc(db, 'companies', companyId);
  await deleteDoc(docRef);
  
  return true;
};

// Get raffles by company ID
export const getRafflesByCompany = async (companyId: string) => {
  if (USE_MOCK_DATA) {
    return mockRaffles.filter(raffle => raffle.companyId === companyId);
  }

  const q = query(
    rafflesCollection, 
    where('companyId', '==', companyId),
    orderBy('createdAt', 'desc')
  );
  
  const snapshot = await getDocs(q);
  return snapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  })) as Raffle[];
};

// Get all active raffles
export const getActiveRaffles = async () => {
  if (USE_MOCK_DATA) {
    return mockRaffles.filter(raffle => raffle.status === 'active');
  }

  const q = query(
    rafflesCollection,
    where('status', '==', 'active'),
    orderBy('createdAt', 'desc')
  );
  
  const snapshot = await getDocs(q);
  return snapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  })) as Raffle[];
};

// Get a specific raffle
export const getRaffle = async (raffleId: string) => {
  if (USE_MOCK_DATA) {
    const raffle = mockRaffles.find(r => r.id === raffleId);
    return raffle || null;
  }

  const docRef = doc(db, 'raffles', raffleId);
  const docSnap = await getDoc(docRef);
  
  if (docSnap.exists()) {
    return {
      id: docSnap.id,
      ...docSnap.data()
    } as Raffle;
  } else {
    return null;
  }
};

// Create a new raffle
export const createRaffle = async (raffle: Omit<Raffle, 'id'>) => {
  if (USE_MOCK_DATA) return { id: 'mock-id-' + Date.now() };
  
  const docRef = await addDoc(rafflesCollection, {
    ...raffle,
    createdAt: Timestamp.now()
  });
  
  return { id: docRef.id };
};

// Update a raffle
export const updateRaffle = async (raffleId: string, data: Partial<Raffle>) => {
  if (USE_MOCK_DATA) return true;
  
  const docRef = doc(db, 'raffles', raffleId);
  await updateDoc(docRef, data);
  
  return true;
};

// Update car specifications for a raffle
export const updateCarSpecifications = async (raffleId: string, specifications: CarSpecifications) => {
  if (USE_MOCK_DATA) return true;
  
  const docRef = doc(db, 'raffles', raffleId);
  await updateDoc(docRef, {
    carSpecifications: specifications
  });
  
  return true;
};

// Delete a raffle
export const deleteRaffle = async (raffleId: string) => {
  if (USE_MOCK_DATA) return true;
  
  const docRef = doc(db, 'raffles', raffleId);
  await deleteDoc(docRef);
  
  return true;
};

// Car features management
export const getAllCarFeatures = async () => {
  if (USE_MOCK_DATA) return [];
  
  const snapshot = await getDocs(carFeaturesCollection);
  return snapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  })) as CarFeature[];
};

export const createCarFeature = async (feature: Omit<CarFeature, 'id'>) => {
  if (USE_MOCK_DATA) return { id: 'mock-id-' + Date.now() };
  
  const docRef = await addDoc(carFeaturesCollection, feature);
  return { id: docRef.id };
};

export const updateCarFeature = async (featureId: string, data: Partial<CarFeature>) => {
  if (USE_MOCK_DATA) return true;
  
  const docRef = doc(db, 'carFeatures', featureId);
  await updateDoc(docRef, data);
  
  return true;
};

export const deleteCarFeature = async (featureId: string) => {
  if (USE_MOCK_DATA) return true;
  
  const docRef = doc(db, 'carFeatures', featureId);
  await deleteDoc(docRef);
  
  return true;
};
